import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { useAuth } from '../context/AuthContext';
import './Login.css';

export default function Login() {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.email || !form.password) {
      toast.error('Please fill all fields');
      return;
    }
    setLoading(true);
    try {
      const user = await login(form.email, form.password);
      toast.success(`Welcome, ${user.name}!`);
      navigate(user.role === 'admin' ? '/admin' : '/guard');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  const fillDemo = (role) => {
    if (role === 'admin') setForm({ email: 'admin@raksham.ai', password: 'admin123' });
    else setForm({ email: 'rajesh@guard.com', password: 'guard123' });
  };

  return (
    <div className="login-page">
      <div className="login-bg">
        <div className="login-grid"></div>
        <div className="login-glow"></div>
      </div>

      <div className="login-container">
        <div className="login-brand">
          <div className="login-logo">🛡</div>
          <h1 className="login-title">NammaRaksham</h1>
          <p className="login-subtitle">Guard Tracking System</p>
        </div>

        <div className="login-card">
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label className="form-label">Email Address</label>
              <input
                type="email"
                className="form-input"
                placeholder="your@email.com"
                value={form.email}
                onChange={e => setForm({ ...form, email: e.target.value })}
                autoComplete="email"
                autoCapitalize="none"
              />
            </div>
            <div className="form-group">
              <label className="form-label">Password</label>
              <input
                type="password"
                className="form-input"
                placeholder="••••••••"
                value={form.password}
                onChange={e => setForm({ ...form, password: e.target.value })}
                autoComplete="current-password"
              />
            </div>
            <button
              type="submit"
              className="btn btn-primary btn-lg btn-full"
              disabled={loading}
            >
              {loading ? (
                <>
                  <span className="loading-spinner" style={{ width: 18, height: 18, borderWidth: 2 }}></span>
                  Signing in...
                </>
              ) : 'Sign In →'}
            </button>
          </form>

          <div className="demo-section">
            <p className="demo-label">Quick Demo Access</p>
            <div className="demo-btns">
              <button className="demo-btn" onClick={() => fillDemo('admin')}>
                <span>👑</span> Admin
              </button>
              <button className="demo-btn" onClick={() => fillDemo('guard')}>
                <span>👮</span> Guard
              </button>
            </div>
          </div>
        </div>

        <p className="login-footer">
          Powered by <strong>NammaRaksham AI</strong> · raksham.ai
        </p>
      </div>
    </div>
  );
}
